mapper.select:
SELECT d.device_id, d.device_name, d.group_id, g.group_name, d.status, d.is_main FROM ess_device d
LEFT JOIN ess_device_group g ON d.group_id = g.group_id
WHERE d.member_id = #{memberId} AND d.deleted_yn = 'N'
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
ORDER BY d.device_id ASC

SELECT user_type
FROM ess_member
WHERE member_id = #{memberId}

SELECT DATE_FORMAT(el.log_date, '%Y-%m') AS label, IFNULL(SUM(el.daily_kwh), 0) AS monthlyKwh, IFNULL(SUM(el.daily_kwh), 0) AS value
FROM energy_log el
JOIN ess_device d ON el.device_id = d.device_id
WHERE d.member_id = #{memberId}
AND el.log_date >= DATE_FORMAT( DATE_SUB( STR_TO_DATE(CONCAT(#{selectedMonth}, '-01'), '%Y-%m-%d'), INTERVAL 5 MONTH ), '%Y-%m-01' )
AND el.log_date <= LAST_DAY( STR_TO_DATE(CONCAT(#{selectedMonth}, '-01'), '%Y-%m-%d') )
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
GROUP BY DATE_FORMAT(el.log_date, '%Y-%m') ORDER BY label ASC

SELECT DATE_FORMAT(el.log_date, '%Y-%m') AS label, IFNULL(SUM(el.cost), 0) AS savedCost, IFNULL(SUM(el.cost), 0) AS value
FROM energy_log el
JOIN ess_device d ON el.device_id = d.device_id
WHERE d.member_id = #{memberId}
AND el.log_date >= DATE_FORMAT( DATE_SUB( STR_TO_DATE(CONCAT(#{selectedMonth}, '-01'), '%Y-%m-%d'), INTERVAL 5 MONTH ), '%Y-%m-01' )
AND el.log_date <= LAST_DAY( STR_TO_DATE(CONCAT(#{selectedMonth}, '-01'), '%Y-%m-%d') )
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
GROUP BY DATE_FORMAT(el.log_date, '%Y-%m') ORDER BY label ASC

SELECT d.device_name AS label, d.device_name AS deviceName, IFNULL(g.group_name, '미지정 그룹') AS groupName, IFNULL(SUM(el.daily_kwh), 0) AS monthlyKwh, IFNULL(SUM(el.daily_kwh), 0) AS value
FROM ess_device d
LEFT JOIN ess_device_group g ON d.group_id = g.group_id
LEFT JOIN energy_log el ON d.device_id = el.device_id AND DATE_FORMAT(el.log_date, '%Y-%m') = #{selectedMonth}
WHERE d.member_id = #{memberId} AND d.deleted_yn = 'N'
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
GROUP BY d.device_id, d.device_name, g.group_name ORDER BY monthlyKwh DESC LIMIT 5
